import java.io.*;
import java.nio.charset.StandardCharsets;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        // Read entire input as a string
        String data = new String(System.in.readAllBytes(), StandardCharsets.UTF_8);
        // Convert escaped "\\n" sequences to real newlines so tokenisation works for both formats
        data = data.replace("\\n", "\n");
        StringTokenizer st = new StringTokenizer(data);
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(st.nextToken());
        while (T-- > 0) {
            int N = Integer.parseInt(st.nextToken());
            int Q = Integer.parseInt(st.nextToken());
            long[] roots = new long[N];
            for (int i = 0; i < N; i++) {
                roots[i] = Long.parseLong(st.nextToken());
            }
            Arrays.sort(roots);
            for (int i = 0; i < Q; i++) {
                long x = Long.parseLong(st.nextToken());
                int idx = Arrays.binarySearch(roots, x);
                if (idx >= 0) {
                    out.append('0');
                } else {
                    int insertPos = -idx - 1;
                    int greater = N - insertPos; // number of roots greater than x
                    out.append((greater & 1) == 0 ? "POSITIVE" : "NEGATIVE");
                }
                out.append('\n');
            }
        }
        // Remove the trailing newline to match exact expected output format
        if (out.length() > 0 && out.charAt(out.length() - 1) == '\n') {
            out.setLength(out.length() - 1);
        }
        System.out.print(out.toString());
    }
}

